final class _UniFfiBinaryWriter {
  final BytesBuilder _builder = BytesBuilder(copy: false);

  void writeU8(int value) => _builder.add([value & 0xFF]);
  void writeI8(int value) => _builder.add([(value) & 0xFF]);
  void writeU16(int value) {
    final data = ByteData(2)..setUint16(0, value, Endian.big);
    _builder.add(data.buffer.asUint8List());
  }
  void writeI16(int value) {
    final data = ByteData(2)..setInt16(0, value, Endian.big);
    _builder.add(data.buffer.asUint8List());
  }
  void writeU32(int value) {
    final data = ByteData(4)..setUint32(0, value, Endian.big);
    _builder.add(data.buffer.asUint8List());
  }
  void writeI32(int value) {
    final data = ByteData(4)..setInt32(0, value, Endian.big);
    _builder.add(data.buffer.asUint8List());
  }
  void writeU64(int value) {
    final data = ByteData(8)..setUint64(0, value, Endian.big);
    _builder.add(data.buffer.asUint8List());
  }
  void writeI64(int value) {
    final data = ByteData(8)..setInt64(0, value, Endian.big);
    _builder.add(data.buffer.asUint8List());
  }
  void writeF32(double value) {
    final data = ByteData(4)..setFloat32(0, value, Endian.big);
    _builder.add(data.buffer.asUint8List());
  }
  void writeF64(double value) {
    final data = ByteData(8)..setFloat64(0, value, Endian.big);
    _builder.add(data.buffer.asUint8List());
  }
  void writeBool(bool value) => writeI8(value ? 1 : 0);
  void writeBytes(Uint8List bytes) => _builder.add(bytes);
  void writeString(String value) {
    final bytes = Uint8List.fromList(utf8.encode(value));
    writeI32(bytes.length);
    writeBytes(bytes);
  }

  Uint8List toBytes() => _builder.takeBytes();
}

final class _UniFfiBinaryReader {
  _UniFfiBinaryReader(this._bytes);
  final Uint8List _bytes;
  int _offset = 0;

  bool get isDone => _offset == _bytes.length;

  ByteData _readData(int len) {
    if (_offset + len > _bytes.length) {
      throw StateError('buffer underflow while decoding UniFFI payload');
    }
    final data = ByteData.sublistView(_bytes, _offset, _offset + len);
    _offset += len;
    return data;
  }

  int readU8() => _readData(1).getUint8(0);
  int readI8() => _readData(1).getInt8(0);
  int readU16() => _readData(2).getUint16(0, Endian.big);
  int readI16() => _readData(2).getInt16(0, Endian.big);
  int readU32() => _readData(4).getUint32(0, Endian.big);
  int readI32() => _readData(4).getInt32(0, Endian.big);
  int readU64() => _readData(8).getUint64(0, Endian.big);
  int readI64() => _readData(8).getInt64(0, Endian.big);
  double readF32() => _readData(4).getFloat32(0, Endian.big);
  double readF64() => _readData(8).getFloat64(0, Endian.big);
  bool readBool() {
    final value = readI8();
    if (value == 0) return false;
    if (value == 1) return true;
    throw StateError('invalid boolean payload value: $value');
  }
  Uint8List readBytes(int len) {
    if (_offset + len > _bytes.length) {
      throw StateError('buffer underflow while decoding UniFFI payload bytes');
    }
    final out = Uint8List.fromList(_bytes.sublist(_offset, _offset + len));
    _offset += len;
    return out;
  }
  String readString() {
    final len = readI32();
    if (len < 0) {
      throw StateError('invalid string length in UniFFI payload: $len');
    }
    return utf8.decode(readBytes(len));
  }
}

void _uniffiWriteChatMessage(ChatMessage value, _UniFfiBinaryWriter writer) {
  writer.writeString(value.role);
  writer.writeString(value.content);
}

Uint8List _uniffiEncodeChatMessage(ChatMessage value) {
  final writer = _UniFfiBinaryWriter();
  _uniffiWriteChatMessage(value, writer);
  return writer.toBytes();
}

ChatMessage _uniffiReadChatMessage(_UniFfiBinaryReader reader) {
  return ChatMessage(
    role: reader.readString(),
    content: reader.readString(),
  );
}

ChatMessage _uniffiDecodeChatMessage(Uint8List bytes) {
  final reader = _UniFfiBinaryReader(bytes);
  final value = _uniffiReadChatMessage(reader);
  if (!reader.isDone) {
    throw StateError('extra bytes remaining while decoding ChatMessage');
  }
  return value;
}

void _uniffiWriteEngineConfig(EngineConfig value, _UniFfiBinaryWriter writer) {
  writer.writeU64(value.contextSize);
  _uniffiWriteBackendPreference(value.backend, writer);
  if (value.bundleRepo == null) {
    writer.writeI8(0);
  } else {
    writer.writeI8(1);
    writer.writeU64(BundleRepoFfiCodec.lower(value.bundleRepo!));
  }
}

Uint8List _uniffiEncodeEngineConfig(EngineConfig value) {
  final writer = _UniFfiBinaryWriter();
  _uniffiWriteEngineConfig(value, writer);
  return writer.toBytes();
}

EngineConfig _uniffiReadEngineConfig(_UniFfiBinaryReader reader) {
  throw UnsupportedError('UniFFI binary decode not fully supported for EngineConfig');
}

EngineConfig _uniffiDecodeEngineConfig(Uint8List bytes) {
  throw UnsupportedError('UniFFI binary decode not fully supported for EngineConfig');
}

void _uniffiWriteGenerateOpts(GenerateOpts value, _UniFfiBinaryWriter writer) {
  writer.writeU32(value.maxTokens);
  writer.writeF32(value.temperature);
  writer.writeF32(value.topP);
  writer.writeU32(value.topK);
  writer.writeF32(value.minP);
  writer.writeF32(value.repetitionPenalty);
  writer.writeI32(value.stopTokens.length);
  for (final item in value.stopTokens) {
    writer.writeU32(item);
  }
  writer.writeBool(value.ignoreEos);
  if (value.grammar == null) {
    writer.writeI8(0);
  } else {
    writer.writeI8(1);
    writer.writeString(value.grammar!);
  }
  writer.writeI32(value.grammarTriggerTokens.length);
  for (final item in value.grammarTriggerTokens) {
    writer.writeU32(item);
  }
  writer.writeU32(value.flushEveryTokens);
  writer.writeU32(value.flushEveryMs);
