  Session newSession(SessionConfig config) {
    _ensureOpen();
    return _ffi.ceraEngineInvokeNewSession(_handle, config);
  }

  /// Look up a special token by name (e.g. `<|im_start|>`,
  /// `<|im_end|>`, `<|tool_call|>`). Returns `None` if the token
